svg.script:
var BASE = 'https://statevec.com';
var ns = 'http://www.w3.org/2000/svg';

/* ── Hashes (read-only) ── */
var HASHES = {
  state:    '2cb87f5f6c4c76da45361c4f934bee8e3d2ed29f0439fc35fbc1ae1727059be9',
  checkins: 'a0c0e74f772b453b6e0352781490c9ac4dfdc781af90b4b3f24b667557c1d4e1',
  votes:    '802e1abbe632e0612827bb2a79e8bc892a90e1b6188550cc587d0e3139763a10',
  questions:'02039b6bc9f648e1ddb26a3b3d1c192c210f68fc624ad875ea2c45974f855dfc',
  comments: 'f28f9c8c5d9344c36a685ebc3817b445b16d76ae1eea257514362d953a36e2e6'
};

/* ── Tension definitions ── */
var TENSIONS = [
  { id: 'tension0', title: 'Cognitive Offloading vs. Deep Learning',
    left: 'Cognitive offloading', right: 'Deep learning',
    leftDesc: 'AI handles routine tasks, freeing cognitive load',
    rightDesc: 'Students must struggle to truly understand' },
  { id: 'tension1', title: 'Personalization vs. Belonging',
    left: 'Personalization', right: 'Belonging',
    leftDesc: 'Tailored AI paths for each learner',
    rightDesc: 'Shared experience builds community' },
  { id: 'tension2', title: 'Assistance vs. Authorship',
    left: 'Assistance', right: 'Authorship',
    leftDesc: 'AI as a helpful collaborator',
    rightDesc: 'Student owns original thought' },
  { id: 'tension3', title: 'Innovation vs. Governance',
    left: 'Innovation', right: 'Governance',
    leftDesc: 'Move fast, explore new tools',
    rightDesc: 'Policies and guardrails first' }
];

/* ── Cached state ── */
var state = {};
var checkins = {};
var votes = {};
var questions = {};
var comments = {};
var currentPhase = '';
var currentTensionIdx = -1;

/* ── Voting countdown state ── */
var VOTING_DURATION = 60;
var votingCountdownInterval = null;
var lastVotingOpen = false;
var votingOpenedAtLocal = 0;

/* ── DOM refs ── */
var connDot = document.getElementById('connDot');
var topParticipants = document.getElementById('topParticipants');
var statusText = document.getElementById('statusText');
var phaseLabel = document.getElementById('phaseLabel');
var clockText = document.getElementById('clockText');

var phaseCheckin = document.getElementById('phaseCheckin');
var phaseTension = document.getElementById('phaseTension');
var phaseResults = document.getElementById('phaseResults');

var checkinCount = document.getElementById('checkinCount');
var nameGrid = document.getElementById('nameGrid');

var tensionTitle = document.getElementById('tensionTitle');
var voteDots = document.getElementById('voteDots');
var meanIndicator = document.getElementById('meanIndicator');
var meanLabel = document.getElementById('meanLabel');
var poleLeft = document.getElementById('poleLeft');
var poleRight = document.getElementById('poleRight');
var voteSummary = document.getElementById('voteSummary');
var tensionPoleALabel = document.getElementById('tensionPoleALabel');
var tensionPoleBLabel = document.getElementById('tensionPoleBLabel');
var tensionPoleADesc = document.getElementById('tensionPoleADesc');
var tensionPoleBDesc = document.getElementById('tensionPoleBDesc');
var questionCount = document.getElementById('questionCount');
var commentCount = document.getElementById('commentCount');
var questionsList = document.getElementById('questionsList');
var commentsList = document.getElementById('commentsList');
var countdownTimer = document.getElementById('countdownTimer');
var countdownLabel = document.getElementById('countdownLabel');

/* ── Helpers ── */
function clearChildren(el) {
  while (el.firstChild) el.removeChild(el.firstChild);
}

function truncate(str, max) {
  if (!str) return '';
  return str.length > max ? str.substring(0, max) + '...' : str;
}

function updateClock() {
  var d = new Date();
  var h = d.getHours();
  var m = d.getMinutes();
  var s = d.getSeconds();
  clockText.textContent =
    (h < 10 ? '0' : '') + h + ':' +
    (m < 10 ? '0' : '') + m + ':' +
    (s < 10 ? '0' : '') + s;
}
setInterval(updateClock, 1000);
updateClock();

/* ── Extract vote list for a tension index ── */
/* Flat keys: 'tension0:userId' = voteValue at top level */
function getVotesForTension(tIdx) {
  var prefix = 'tension' + tIdx + ':';
  var voteList = [];
  var val = votes.val || votes;
  if (!val || typeof val !== 'object') return voteList;

  var allKeys = Object.keys(val);
  for (var i = 0; i < allKeys.length; i++) {
    if (allKeys[i].indexOf(prefix) === 0) {
      var v = val[allKeys[i]];
      if (typeof v === 'number') {
        voteList.push(v);
      }
    }
  }
  return voteList;
}

/* ── Compute std deviation for a vote list ── */
function stdDev(arr) {
  if (arr.length < 2) return 0;
  var sum = 0;
  for (var i = 0; i < arr.length; i++) sum += arr[i];
  var mean = sum / arr.length;
  var sqDiffSum = 0;
  for (var j = 0; j < arr.length; j++) {
    var d = arr[j] - mean;
    sqDiffSum += d * d;
  }
  return Math.sqrt(sqDiffSum / arr.length);
}

/* ── Voting countdown ── */
function startVotingCountdown() {
  votingOpenedAtLocal = Date.now();
  if (votingCountdownInterval) clearInterval(votingCountdownInterval);
  updateCountdownDisplay();
  votingCountdownInterval = setInterval(updateCountdownDisplay, 500);
}

function stopVotingCountdown() {
  if (votingCountdownInterval) {
    clearInterval(votingCountdownInterval);
    votingCountdownInterval = null;
  }
  countdownTimer.textContent = 'VOTING CLOSED';
  countdownTimer.setAttribute('visibility', 'visible');
  countdownTimer.setAttribute('fill', '#ef4444');
  countdownTimer.setAttribute('font-size', '24');
  countdownLabel.setAttribute('visibility', 'hidden');
}

function updateCountdownDisplay() {
  if (!votingOpenedAtLocal) return;
  var elapsed = Math.floor((Date.now() - votingOpenedAtLocal) / 1000);
  var remaining = Math.max(0, VOTING_DURATION - elapsed);
  var mins = Math.floor(remaining / 60);
  var secs = remaining % 60;
  countdownTimer.textContent = mins + ':' + (secs < 10 ? '0' : '') + secs;
  countdownTimer.setAttribute('visibility', 'visible');
  countdownTimer.setAttribute('fill', remaining <= 10 ? '#ef4444' : '#f1f5f9');
  countdownTimer.setAttribute('font-size', remaining <= 10 ? '42' : '36');
  countdownLabel.setAttribute('visibility', 'visible');
  countdownLabel.textContent = remaining > 0 ? 'voting open' : 'VOTING CLOSED';
  if (remaining <= 0) {
    countdownTimer.textContent = 'VOTING CLOSED';
    countdownTimer.setAttribute('fill', '#ef4444');
    countdownTimer.setAttribute('font-size', '24');
    countdownLabel.setAttribute('visibility', 'hidden');
    if (votingCountdownInterval) {
      clearInterval(votingCountdownInterval);
      votingCountdownInterval = null;
    }
  }
}

function hideCountdown() {
  countdownTimer.setAttribute('visibility', 'hidden');
  countdownLabel.setAttribute('visibility', 'hidden');
  if (votingCountdownInterval) {
    clearInterval(votingCountdownInterval);
    votingCountdownInterval = null;
  }
}

/* ── Phase switching ── */
function showPhase(phase) {
  phaseCheckin.setAttribute('visibility', phase === 'checkin' ? 'visible' : 'hidden');
  phaseTension.setAttribute('visibility', phase === 'tension' ? 'visible' : 'hidden');
  phaseResults.setAttribute('visibility', phase === 'results' ? 'visible' : 'hidden');
  currentPhase = phase;
  phaseLabel.textContent = phase ? phase.toUpperCase() : '--';
  if (phase !== 'tension') {
    hideCountdown();
  }
}

/* ── Render: Check-in phase ── */
function renderCheckin() {
  var val = checkins.val || checkins;
  var names = [];
  if (val && typeof val === 'object') {
    var keys = Object.keys(val);
    for (var i = 0; i < keys.length; i++) {
      var entry = val[keys[i]];
      if (typeof entry === 'string') {
        names.push(entry);
      } else if (entry && entry.name) {
        names.push(entry.name);
      } else if (typeof entry === 'object' && entry !== null) {
        var eKeys = Object.keys(entry);
        for (var j = 0; j < eKeys.length; j++) {
          var sub = entry[eKeys[j]];
          if (typeof sub === 'string') names.push(sub);
          else if (sub && sub.name) names.push(sub.name);
        }
      }
    }
  }

  checkinCount.textContent = names.length + ' checked in';
  topParticipants.textContent = names.length + ' participants';

  clearChildren(nameGrid);
  var cols = 8;
  var cellW = 130;
  var cellH = 24;
  for (var k = 0; k < names.length; k++) {
    var col = k % cols;
    var row = Math.floor(k / cols);
    var t = document.createElementNS(ns, 'text');
    t.setAttribute('x', col * cellW);
    t.setAttribute('y', row * cellH + 16);
    t.setAttribute('font-family', 'monospace');
    t.setAttribute('font-size', '12');
    t.setAttribute('fill', '#94a3b8');
    t.textContent = truncate(names[k], 14);
    nameGrid.appendChild(t);
  }
}

/* ── Render: Tension phase ── */
function renderTension(tIdx) {
  var t = TENSIONS[tIdx];
  if (!t) return;
  currentTensionIdx = tIdx;

  tensionTitle.textContent = t.title;
  /* Dynamic pole names on spectrum (requirement 7) */
  poleLeft.textContent = t.left;
  poleRight.textContent = t.right;
  tensionPoleALabel.textContent = t.left;
  tensionPoleBLabel.textContent = t.right;
  tensionPoleADesc.textContent = t.leftDesc;
  tensionPoleBDesc.textContent = t.rightDesc;

  /* Nav dots */
  for (var n = 0; n < 4; n++) {
    var dot = document.getElementById('navDot' + n);
    if (dot) {
      dot.setAttribute('fill', n === tIdx ? '#c9a227' : '#1e293b');
    }
  }

  /* Votes for this tension (requirement 1,3: use tension0..3 keys, parse {userId:val}) */
  var voteList = getVotesForTension(tIdx);

  /* Draw vote dots on spectrum (1=far left, 5=far right over 720px) */
  clearChildren(voteDots);
  var SPECTRUM_W = 720;
  var total = voteList.length;
  var sum = 0;

  /* Count votes at each position for stacking */
  var posCount = {};
  for (var vi = 0; vi < voteList.length; vi++) {
    var v = Math.max(1, Math.min(5, voteList[vi]));
    sum += v;
    var posKey = Math.round(v * 10);
    if (!posCount[posKey]) posCount[posKey] = 0;
    posCount[posKey]++;
  }

  /* Draw dots */
  var posDrawn = {};
  for (var vi2 = 0; vi2 < voteList.length; vi2++) {
    var vv = Math.max(1, Math.min(5, voteList[vi2]));
    var posKey2 = Math.round(vv * 10);
    if (!posDrawn[posKey2]) posDrawn[posKey2] = 0;
    var stackIdx = posDrawn[posKey2];
    posDrawn[posKey2]++;

    var cx = ((vv - 1) / 4) * SPECTRUM_W;
    /* Stack vertically: offset by -14 per stacked dot */
    var cy = -8 - (stackIdx * 14);

    var circle = document.createElementNS(ns, 'circle');
    circle.setAttribute('cx', cx);
    circle.setAttribute('cy', cy);
    circle.setAttribute('r', 6);
    circle.setAttribute('fill', '#f1f5f9');
    circle.setAttribute('opacity', '0.7');
    circle.setAttribute('stroke', '#0a0e1a');
    circle.setAttribute('stroke-width', '1');
    voteDots.appendChild(circle);
  }

  /* Mean */
  var mean = total > 0 ? sum / total : 3;
  var meanX = ((mean - 1) / 4) * SPECTRUM_W;
  meanIndicator.setAttribute('points',
    meanX + ',122 ' + (meanX - 6) + ',134 ' + (meanX + 6) + ',134');
  meanLabel.setAttribute('x', meanX);
  meanLabel.textContent = total > 0 ? 'mean: ' + mean.toFixed(1) : 'mean';

  voteSummary.textContent = total + ' vote' + (total !== 1 ? 's' : '');
}

/* ── Render: Questions (requirement 4: filter by tension === currentTension as number) ── */
function renderQuestions(tIdx) {
  clearChildren(questionsList);
  var val = questions.val || questions;
  var qList = [];

  if (val && typeof val === 'object') {
    var keys = Object.keys(val);
    for (var i = 0; i < keys.length; i++) {
      var q = val[keys[i]];
      if (q && typeof q === 'object') {
        /* Phone writes tension as a number: question.tension === currentTension */
        if (typeof q.tension === 'number' && q.tension === tIdx) {
          /* Count upvotes from flat 'upvote:qId:*' keys */
          var upvotes = 0;
          var upPrefix = 'upvote:' + keys[i] + ':';
          for (var ui = 0; ui < keys.length; ui++) {
            if (keys[ui].indexOf(upPrefix) === 0 && val[keys[ui]]) upvotes++;
          }
          qList.push({
            text: q.text || keys[i],
            upvotes: upvotes,
            highlighted: q.highlighted || false,
            name: q.author || 'anonymous'
          });
        }
      }
    }
  }

  /* Sort by upvotes descending */
  qList.sort(function(a, b) { return b.upvotes - a.upvotes; });
  var top5 = qList.slice(0, 5);

  questionCount.textContent = qList.length + '';

  for (var qi = 0; qi < top5.length; qi++) {
    var q2 = top5[qi];
    var y = qi * 56;

    /* Background */
    var bg = document.createElementNS(ns, 'rect');
    bg.setAttribute('x', 0);
    bg.setAttribute('y', y);
    bg.setAttribute('width', 472);
    bg.setAttribute('height', 50);
    bg.setAttribute('rx', 6);
    bg.setAttribute('fill', '#111827');
    bg.setAttribute('stroke', q2.highlighted ? '#c9a227' : '#1e293b');
    bg.setAttribute('stroke-width', q2.highlighted ? '2' : '1');
    questionsList.appendChild(bg);

    /* Star if highlighted */
    if (q2.highlighted) {
      var star = document.createElementNS(ns, 'text');
      star.setAttribute('x', 12);
      star.setAttribute('y', y + 24);
      star.setAttribute('font-family', 'monospace');
      star.setAttribute('font-size', '16');
      star.setAttribute('fill', '#c9a227');
      star.textContent = '\u2605';
      questionsList.appendChild(star);
    }

    /* Question text (requirement 9: font-size 16 for readability) */
    var qt = document.createElementNS(ns, 'text');
    qt.setAttribute('x', q2.highlighted ? 34 : 12);
    qt.setAttribute('y', y + 22);
    qt.setAttribute('font-family', 'monospace');
    qt.setAttribute('font-size', '16');
    qt.setAttribute('fill', '#f1f5f9');
    qt.textContent = truncate(q2.text, 42);
    questionsList.appendChild(qt);

    /* Author */
    var qa = document.createElementNS(ns, 'text');
    qa.setAttribute('x', q2.highlighted ? 34 : 12);
    qa.setAttribute('y', y + 40);
    qa.setAttribute('font-family', 'monospace');
    qa.setAttribute('font-size', '11');
    qa.setAttribute('fill', '#94a3b8');
    qa.textContent = q2.name;
    questionsList.appendChild(qa);

    /* Upvote count */
    var uv = document.createElementNS(ns, 'text');
    uv.setAttribute('x', 456);
    uv.setAttribute('y', y + 24);
    uv.setAttribute('font-family', 'monospace');
    uv.setAttribute('font-size', '14');
    uv.setAttribute('fill', '#3b82f6');
    uv.setAttribute('text-anchor', 'end');
    uv.textContent = '\u25B2 ' + q2.upvotes;
    questionsList.appendChild(uv);
  }
}

/* ── Render: Comments (requirement 5: filter by tension === currentTension as number) ── */
function renderComments(tIdx) {
  clearChildren(commentsList);
  var val = comments.val || comments;
  var cList = [];

  if (val && typeof val === 'object') {
    var keys = Object.keys(val);
    for (var i = 0; i < keys.length; i++) {
      var c = val[keys[i]];
      if (c && typeof c === 'object') {
        /* Phone writes tension as a number: comment.tension === currentTension */
        if (typeof c.tension === 'number' && c.tension === tIdx) {
          cList.push({
            text: c.text || c.msg || c.comment || '',
            name: c.author || c.name || 'anonymous',
            ts: c.t || c.ts || c.time || 0
          });
        }
      }
    }
  }

  /* Sort by timestamp descending, take last 4 */
  cList.sort(function(a, b) { return b.ts - a.ts; });
  var last4 = cList.slice(0, 4);

  commentCount.textContent = cList.length + '';

  for (var ci = 0; ci < last4.length; ci++) {
    var c2 = last4[ci];
    var y = ci * 56;

    var bg = document.createElementNS(ns, 'rect');
    bg.setAttribute('x', 0);
    bg.setAttribute('y', y);
    bg.setAttribute('width', 472);
    bg.setAttribute('height', 50);
    bg.setAttribute('rx', 6);
    bg.setAttribute('fill', '#111827');
    bg.setAttribute('stroke', '#1e293b');
    commentsList.appendChild(bg);

    /* Comment author (requirement 9: larger text) */
    var cn = document.createElementNS(ns, 'text');
    cn.setAttribute('x', 12);
    cn.setAttribute('y', y + 20);
    cn.setAttribute('font-family', 'monospace');
    cn.setAttribute('font-size', '12');
    cn.setAttribute('fill', '#c9a227');
    cn.textContent = c2.name;
    commentsList.appendChild(cn);

    /* Comment text (requirement 9: font-size 14 for readability) */
    var ct = document.createElementNS(ns, 'text');
    ct.setAttribute('x', 12);
    ct.setAttribute('y', y + 40);
    ct.setAttribute('font-family', 'monospace');
    ct.setAttribute('font-size', '14');
    ct.setAttribute('fill', '#f1f5f9');
    ct.textContent = truncate(c2.text, 46);
    commentsList.appendChild(ct);
  }
}

/* ── Render: Results phase (requirement 8: narrative stats) ── */
function renderResults() {
  var totalQ = 0;
  var totalC = 0;
  var totalP = 0;

  /* Count participants from checkins */
  var cVal = checkins.val || checkins;
  if (cVal && typeof cVal === 'object') {
    totalP = Object.keys(cVal).length;
  }
  topParticipants.textContent = totalP + ' participants';

  /* Count questions */
  var qVal = questions.val || questions;
  if (qVal && typeof qVal === 'object') {
    totalQ = Object.keys(qVal).length;
  }

  /* Count comments */
  var cmVal = comments.val || comments;
  if (cmVal && typeof cmVal === 'object') {
    totalC = Object.keys(cmVal).length;
  }

  document.getElementById('resultTotalParticipants').textContent = totalP;
  document.getElementById('resultTotalQuestions').textContent = totalQ;
  document.getElementById('resultTotalComments').textContent = totalC;

  /* Collect std devs for narrative */
  var allStdDevs = [];
  var allMeans = [];
  var allVoteCounts = [];

  /* Mini spectrum for each tension */
  for (var ti = 0; ti < 4; ti++) {
    var tDef = TENSIONS[ti];
    document.getElementById('resultTitle' + ti).textContent = tDef.title;
    document.getElementById('resultSub' + ti).textContent = tDef.left + ' vs. ' + tDef.right;
    document.getElementById('resultLeftLabel' + ti).textContent = tDef.left;
    document.getElementById('resultRightLabel' + ti).textContent = tDef.right;

    /* Use same vote extraction as tension phase (requirement 1) */
    var vList = getVotesForTension(ti);

    document.getElementById('resultVotes' + ti).textContent = vList.length + ' votes';
    allVoteCounts.push(vList.length);

    var dotsG = document.getElementById('resultDots' + ti);
    clearChildren(dotsG);

    var miniW = 240;
    var sum = 0;
    var posCount = {};
    for (var k = 0; k < vList.length; k++) {
      var vv = Math.max(1, Math.min(5, vList[k]));
      sum += vv;
      var pk = Math.round(vv * 10);
      if (!posCount[pk]) posCount[pk] = 0;
      posCount[pk]++;
    }

    var posDrawn = {};
    for (var k2 = 0; k2 < vList.length; k2++) {
      var vv2 = Math.max(1, Math.min(5, vList[k2]));
      var pk2 = Math.round(vv2 * 10);
      if (!posDrawn[pk2]) posDrawn[pk2] = 0;
      var si = posDrawn[pk2];
      posDrawn[pk2]++;

      var cx = ((vv2 - 1) / 4) * miniW;
      var cy = -4 - (si * 10);

      var circle = document.createElementNS(ns, 'circle');
      circle.setAttribute('cx', cx);
      circle.setAttribute('cy', cy);
      circle.setAttribute('r', 4);
      circle.setAttribute('fill', '#f1f5f9');
      circle.setAttribute('opacity', '0.7');
      circle.setAttribute('stroke', '#0a0e1a');
      circle.setAttribute('stroke-width', '1');
      dotsG.appendChild(circle);
    }

    var mean = vList.length > 0 ? sum / vList.length : 3;
    var sd = stdDev(vList);
    allMeans.push(mean);
    allStdDevs.push(sd);

    var meanX = 20 + ((mean - 1) / 4) * miniW;
    document.getElementById('resultMean' + ti).textContent = vList.length > 0 ? 'mean: ' + mean.toFixed(1) : 'mean: --';
    document.getElementById('resultStdDev' + ti).textContent = vList.length > 0 ? 'std dev: ' + sd.toFixed(2) : 'std dev: --';
    var arrow = document.getElementById('resultMeanArrow' + ti);
    arrow.setAttribute('points',
      meanX + ',160 ' + (meanX - 4) + ',170 ' + (meanX + 4) + ',170');
  }

  /* Narrative stats (requirement 8) */
  var mostContestedIdx = 0;
  var strongestConsensusIdx = 0;
  var maxSD = -1;
  var minSD = 999;
  var anyVotes = false;

  for (var si2 = 0; si2 < 4; si2++) {
    if (allVoteCounts[si2] > 0) {
      anyVotes = true;
      if (allStdDevs[si2] > maxSD) {
        maxSD = allStdDevs[si2];
        mostContestedIdx = si2;
      }
      if (allStdDevs[si2] < minSD) {
        minSD = allStdDevs[si2];
        strongestConsensusIdx = si2;
      }
    }
  }

  if (anyVotes) {
    document.getElementById('resultMostContested').textContent =
      'Most contested: ' + TENSIONS[mostContestedIdx].title + ' (SD ' + maxSD.toFixed(2) + ')';
    document.getElementById('resultStrongestConsensus').textContent =
      'Strongest consensus: ' + TENSIONS[strongestConsensusIdx].title + ' (SD ' + minSD.toFixed(2) + ')';
  } else {
    document.getElementById('resultMostContested').textContent = 'Most contested: no votes yet';
    document.getElementById('resultStrongestConsensus').textContent = 'Strongest consensus: no votes yet';
  }

  document.getElementById('resultNarrativeTotals').textContent =
    totalP + ' participants / ' + totalQ + ' questions / ' + totalC + ' comments';

  /* Top question per tension (requirement 8) */
  for (var tq = 0; tq < 4; tq++) {
    var topQEl = document.getElementById('resultTopQ' + tq);
    var topQText = 'T' + (tq + 1) + ': --';
    if (qVal && typeof qVal === 'object') {
      var qKeys = Object.keys(qVal);
      var bestQ = null;
      var bestUp = -1;
      for (var qi2 = 0; qi2 < qKeys.length; qi2++) {
        var qq = qVal[qKeys[qi2]];
        if (qq && typeof qq === 'object' && typeof qq.tension === 'number' && qq.tension === tq) {
          var ups = 0;
          var upPfx = 'upvote:' + qKeys[qi2] + ':';
          for (var upk = 0; upk < qKeys.length; upk++) {
            if (qKeys[upk].indexOf(upPfx) === 0 && qVal[qKeys[upk]]) ups++;
          }
          if (ups > bestUp) {
            bestUp = ups;
            bestQ = qq.text || '';
          }
        }
      }
      if (bestQ) {
        topQText = 'T' + (tq + 1) + ': "' + truncate(bestQ, 55) + '" (' + bestUp + ' upvotes)';
      }
    }
    topQEl.textContent = topQText;
  }
}

/* ── Fetch helper ── */
function fetchHash(hash) {
  return fetch(BASE + '/v/' + hash).then(function(r) {
    if (r.ok) return r.json();
    return null;
  }).catch(function() { return null; });
}

/* ── Main poll ── */
function poll() {
  var fetches = [
    fetchHash(HASHES.state),
    fetchHash(HASHES.checkins),
    fetchHash(HASHES.votes),
    fetchHash(HASHES.questions),
    fetchHash(HASHES.comments)
  ];

  Promise.all(fetches).then(function(results) {
    var stateData = results[0];
    var checkinsData = results[1];
    var votesData = results[2];
    var questionsData = results[3];
    var commentsData = results[4];

    connDot.setAttribute('fill', '#22c55e');
    statusText.textContent = 'connected | last poll: ' + new Date().toLocaleTimeString();

    if (stateData && stateData.val) state = stateData.val;
    if (checkinsData && checkinsData.val) checkins = { val: checkinsData.val };
    else if (checkinsData) checkins = checkinsData;
    if (votesData && votesData.val) votes = { val: votesData.val };
    else if (votesData) votes = votesData;
    if (questionsData && questionsData.val) questions = { val: questionsData.val };
    else if (questionsData) questions = questionsData;
    if (commentsData && commentsData.val) comments = { val: commentsData.val };
    else if (commentsData) comments = commentsData;

    /* Determine phase */
    var phase = 'checkin';
    if (state && state.phase) {
      phase = state.phase;
    }

    /* Determine tension index (requirement 2: read state.currentTension) */
    var tIdx = 0;
    if (state && typeof state.currentTension === 'number') {
      tIdx = state.currentTension;
    }

    /* Handle voting countdown (requirement 6) */
    var isVotingOpen = !!(state && state.votingOpen);
    if (isVotingOpen && !lastVotingOpen) {
      /* Voting just opened -- start countdown */
      startVotingCountdown();
    } else if (!isVotingOpen && lastVotingOpen) {
      /* Voting just closed */
      stopVotingCountdown();
    } else if (!isVotingOpen && !lastVotingOpen && phase === 'tension') {
      /* Voting not open, no countdown needed but keep closed msg briefly */
      if (!votingOpenedAtLocal) {
        hideCountdown();
      }
    }
    lastVotingOpen = isVotingOpen;

    /* Update participant count */
    var cVal2 = checkins.val || checkins;
    var pCount = 0;
    if (cVal2 && typeof cVal2 === 'object') {
      pCount = Object.keys(cVal2).length;
    }
    topParticipants.textContent = pCount + ' participants';

    /* Show appropriate phase */
    showPhase(phase);

    if (phase === 'checkin') {
      renderCheckin();
    } else if (phase === 'tension') {
      renderTension(tIdx);
      renderQuestions(tIdx);
      renderComments(tIdx);
    } else if (phase === 'results') {
      renderResults();
    }

  }).catch(function(err) {
    connDot.setAttribute('fill', '#ef4444');
    statusText.textContent = 'error: ' + (err.message || 'poll failed');
  });
}

/* ── Init ── */
showPhase('checkin');
poll();
setInterval(poll, 2000);
